return items
  .map(item => {
    let cep = item.json["CEP Destino"];
    if (!cep) return null;

    // Normaliza: remove tudo que não é número
    cep = String(cep).replace(/\D/g, '');

    // Completa com zeros à esquerda
    cep = cep.padStart(8, '0');

    // Validação final
    if (cep.length !== 8) return null;

    return {
      json: {
        ...item.json,
        cep_normalizado: cep
      }
    };
  })
  .filter(Boolean);

return items.map(item => {
  const data = item.json;

  let uf = 'Erro API';

  if (!data.erro && data.uf) {
    uf = data.uf;
  } else if (data.erro) {
    uf = 'CEP inválido';
  }

  return {
    json: {
      ...item.json,
      estado_api: uf
    }
  };
