function ufFromCep(cep) {
  const n = parseInt(cep.slice(0, 3), 10);

  if (n >= 10 && n <= 199) return 'SP';
  if (n >= 200 && n <= 289) return 'RJ';
  if (n >= 290 && n <= 299) return 'ES';
  if (n >= 300 && n <= 399) return 'MG';
  if (n >= 400 && n <= 489) return 'BA';
  if (n >= 490 && n <= 499) return 'SE';
  if (n >= 500 && n <= 569) return 'PE';
  if (n >= 570 && n <= 579) return 'AL';
  if (n >= 580 && n <= 589) return 'PB';
  if (n >= 590 && n <= 599) return 'RN';
  if (n >= 600 && n <= 639) return 'CE';
  if (n >= 640 && n <= 649) return 'PI';
  if (n >= 650 && n <= 659) return 'MA';
  if (n >= 660 && n <= 688) return 'PA';
  if (n === 689) return 'AP';
  if (n >= 690 && n <= 692) return 'AM';
  if (n === 693) return 'RR';
  if (n >= 694 && n <= 698) return 'AM';
  if (n === 699) return 'AC';
  if (n >= 700 && n <= 727) return 'DF';
  if (n >= 728 && n <= 767) return 'GO';
  if (n >= 768 && n <= 769) return 'RO';
  if (n >= 770 && n <= 779) return 'TO';
  if (n >= 780 && n <= 788) return 'MT';
  if (n >= 790 && n <= 799) return 'MS';
  if (n >= 800 && n <= 879) return 'PR';
  if (n >= 880 && n <= 899) return 'SC';
  if (n >= 900 && n <= 999) return 'RS';

  return 'CEP inválido';
}

return items.map(item => {
  let cep = item.json["CEP Destino"];

  if (!cep) {
    return {
      json: {
        ...item.json,
        estado_calculado: 'Sem CEP',
        validacao: false
      }
    };
  }

  cep = String(cep).replace(/\D/g, '').padStart(8, '0');

  if (cep.length !== 8 || /^0{8}$/.test(cep)) {
    return {
      json: {
        ...item.json,
        cep_normalizado: cep,
        estado_calculado: 'CEP inválido',
        validacao: false
      }
    };
  }

  const uf = ufFromCep(cep);

  return {
    json: {
      ...item.json,
      cep_normalizado: cep,
      estado_calculado: uf,
      validacao: uf !== 'CEP inválido'
    }
  };
});
